  "YOKOSE-BATH-HOUSE": {
   "name": "YOKOSE-BATH-HOUSE",
   "file": "quake.zil",
   "line": 726,
   "endLine": 761,
   "desc": "Bath House",
   "ldesc": "This is the bath house outside the inn at Yokose.  The first floor of\nthe inn is to the west.",
   "fdesc": "Toranaga tells everyone he will head up the east road toward Atami\nand Odawara, thence over the mountains to Yedo.  Mariko is given\npermission to go to Osaka.  \"But first you'll go directly from here\nto Mishima, then continue on to Yedo with the Anjin-san.  You're\nresponsible for him until you arrive.\"|\n|\nBuntaro turns to Mariko.  \"Sayonara -- until I see you at Osaka.  When\nwe meet there or when you return from there, then we begin again.\"|\n|\n\"Sayonara, my Lord.\"  Mariko bows.  He swings into his saddle and\nis off toward the head of the column.|\n|\n\"Go with God,\" she says, and you watch her eyes following Buntaro.|\n|\nThe journey to Mishima takes nine days, and every night, for part of\nthe night, you are together.  Secretly.  Your escort, Captain Akira\nYoshinaka, unwittingly makes it easier by placing you in adjoining rooms.|\n|\nTonight the group arrives at Yokose Spa, road-weary and dirty from the\njourney.  Everyone is anxious for a bath and a night's sleep -- or\nother relaxation.",
   "loc": "ROOMS",
   "flags": [
    "ONBIT",
    "RMUNGBIT"
   ],
   "synonyms": [
    "BATH",
    "HOUSE"
   ],
   "adjectives": [
    "BATH"
   ],
   "action": "YOKOSE-BATH-HOUSE-F",
   "descfcn": null,
   "contfcn": null,
   "globals": [],
   "pseudo": [],
   "otherProps": {
    "SCENE": [
     "S-JOURNEY"
    ],
    "SCORE": [
     "3"
    ],
    "AFTER": [
     "JOURNEY-AFTER-F"
    ]
   },
   "exits": [
    {
     "to": "YOKOSE-FIRST-FLOOR",
     "kind": "unconditional",
     "condition": null,
     "else": null,
     "per": null,
     "message": null,
     "dir": "WEST"
    }
   ],
   "contents": [
    "ROBE",
    "TOWEL",
    "YOKOSE-BATHTUB"
   ],
   "source": "<ROOM YOKOSE-BATH-HOUSE\n      (LOC ROOMS)\n      (SCENE S-JOURNEY)\n      (SCORE 3)\n      (AFTER JOURNEY-AFTER-F)\n      (FDESC\n\"Toranaga tells everyone he will head up the east road toward Atami\nand Odawara, thence over the mountains to Yedo.  Mariko is given\npermission to go to Osaka.  \\\"But first you'll go directly from here\nto Mishima, then continue on to Yedo with the Anjin-san.  You're\nresponsible for him until you arrive.\\\"|\n|\nBuntaro turns to Mariko.  \\\"Sayonara -- until I see you at Osaka.  When\nwe meet there or when you return from there, then we begin again.\\\"|\n|\n\\\"Sayonara, my Lord.\\\"  Mariko bows.  He swings into his saddle and\nis off toward the head of the column.|\n|\n\\\"Go with God,\\\" she says, and you watch her eyes following Buntaro.|\n|\nThe journey to Mishima takes nine days, and every night, for part of\nthe night, you are together.  Secretly.  Your escort, Captain Akira\nYoshinaka, unwittingly makes it easier by placing you in adjoining rooms.|\n|\nTonight the group arrives at Yokose Spa, road-weary and dirty from the\njourney.  Everyone is anxious for a bath and a night's sleep -- or\nother relaxation.\")\n      (DESC \"Bath House\")\n      (LDESC\n\"This is the bath house outside the inn at Yokose.  The first floor of\nthe inn is to the west.\")\n      (SYNONYM BATH HOUSE)\n      (ADJECTIVE BATH)\n      (WEST TO YOKOSE-FIRST-FLOOR)\n      (FLAGS ONBIT RMUNGBIT)\n      (ACTION YOKOSE-BATH-HOUSE-F)>",
   "referencedBy": [
    "GLOBAL-WATER-F",
    "YOKOSE-BATH-HOUSE-F",
    "I-YOKOSE-BATH",
    "I-YOSHINAKA",
    "YOKOSE-NEIGHBOR?"
   ]
  },
