  "SALAMON-F": {
   "name": "SALAMON-F",
   "file": "erasmus.zil",
   "line": 3044,
   "endLine": 3054,
   "source": "<ROUTINE SALAMON-F (\"OPT\" (RARG <>))\n\t <COND (<RARG? SUBJ>\n\t\t<RFALSE>)\n\t       (<RARG? WINNER>\n\t\t<TELL\nCTHE ,WINNER \" responds with gestures conveying little enthusiasm.\" CR>)\n\t       (<VERB? WHO>\n\t\t<TELL \"Salamon is a mute.\" CR>)\n\t       (<HOSTILE-VERB?>\n\t\t<TELL\n\"In the end, you can't actually bring yourself to do it.\" CR>)>>"
  },
  "VAN-NEKK-F": {
   "name": "VAN-NEKK-F",
   "file": "erasmus.zil",
   "line": 3064,
   "endLine": 3085,
   "source": "<ROUTINE VAN-NEKK-F (\"OPT\" (RARG <>))\n\t <COND ;(<RARG? SUBJ>\n\t\t<RFALSE>)\n\t       (<RARG? WINNER>\n\t\t<COND (<P? TELL-ME-ABOUT (APPLE ROPER)>\n\t\t       <TELL\n\"Van Nekk points angrily at Roper.  \\\"He took it, Pilot!  He said you\nwere hoarding food!\\\"\" CR>)\n\t\t      (<P? (RAISE REPAIR LOWER) FORESAILS>\n\t\t       <RFALSE>)\n\t\t      (<SEND-HIM-OUT?>\n\t\t       <SETG WINNER ,PLAYER>\n\t\t       <PERFORM ,V?SEND ,VAN-NEKK ,ROOMS>\n\t\t       <RTRUE>)\n\t\t      (ELSE\n\t\t       <TELL\nG\"The only responses are muttered curses in Dutch.\" CR>)>)\n\t       (<RARG? <>>\n\t\t<COND (<P? SEND VAN-NEKK>\n\t\t       <TELL\n\"\\\"I'd go, Pilot, but it's not my watch.  It's Vinck's watch, I think, and\nGinsel's, and Maetsukker's, if I've not gone crazed.\\\"  He smiles wanly.\" CR>)>)>>"
  },
  "CROOCQ-F": {
   "name": "CROOCQ-F",
   "file": "erasmus.zil",
   "line": 3095,
   "endLine": 3120,
   "source": "<ROUTINE CROOCQ-F (\"OPT\" (RARG <>))\n\t <COND (<RARG? SUBJ>\n\t\t<RFALSE>)\n\t       (<RARG? WINNER>\n\t\t<COND (<P? TELL-ME-ABOUT (APPLE ROPER)>\n\t\t       <TELL\n\"Croocq says, \\\"I don't know anything about it, Pilot.\\\"\" CR>)\n\t\t      (<P? (RAISE REPAIR LOWER) FORESAILS>\n\t\t       <RFALSE>)\n\t\t      (<SEND-HIM-OUT?>\n\t\t       <SETG WINNER ,PLAYER>\n\t\t       <PERFORM ,V?SEND ,CROOCQ ,ROOMS>\n\t\t       <RTRUE>)\n\t\t      (ELSE\n\t\t       <TELL\nG\"The only responses are muttered curses in Dutch.\" CR>)>)\n\t       (<VERB? TELL>\n\t\t<COND (<OR <IN? ,CROOCQ ,CAULDRON>\n\t\t\t   <IN? ,CROOCQ ,VILLAGE-SQUARE>>\n\t\t       <TELL\n\"He's in no condition to respond.\" CR>\n\t\t       <END-QUOTE>\n\t\t       <RFATAL>)>)\n\t       (<P? SEND CROOCQ>\n\t\t<TELL\n\"He's too far gone to go on deck; almost too tired to stand.\" CR>)>>"
  },
  "SEND-HIM-OUT?": {
   "name": "SEND-HIM-OUT?",
   "file": "erasmus.zil",
   "line": 3122,
   "endLine": 3128,
   "source": "<ROUTINE SEND-HIM-OUT? ()\n\t <COND (<SCENE? ,S-ERASMUS>\n\t\t<OR <VERB? REPLACE>\n\t\t    <P? FOLLOW ME>\n\t\t    <P? WALK (P?UP P?OUT)>\n\t\t    <P? (STEP-ON TAKE BOARD WALK-TO CLIMB-ON)\n\t\t\t(DECK BRIDGE-OF-ERASMUS ON-DECK)>>)>>"
  },
  "TELL-DIRECTION": {
   "name": "TELL-DIRECTION",
   "file": "globals.zil",
   "line": 93,
   "endLine": 115,
   "source": "<ROUTINE TELL-DIRECTION (DIR)\n\t <COND (<EQUAL? .DIR ,P?SOUTH>\n\t\t<TELL \"south\">)\n\t       (<EQUAL? .DIR ,P?NORTH>\n\t\t<TELL \"north\">)\n\t       (<EQUAL? .DIR ,P?WEST>\n\t\t<TELL \"west\">)\n\t       (<EQUAL? .DIR ,P?EAST>\n\t\t<TELL \"east\">)\n\t       (<EQUAL? .DIR ,P?SW>\n\t\t<TELL \"southwest\">)\n\t       (<EQUAL? .DIR ,P?NW>\n\t\t<TELL \"northwest\">)\n\t       (<EQUAL? .DIR ,P?SE>\n\t\t<TELL \"southeast\">)\n\t       (<EQUAL? .DIR ,P?NE>\n\t\t<TELL \"northeast\">)\n\t       (<EQUAL? .DIR ,P?PORT>\n\t\t<TELL \"port\">)\n\t       (<EQUAL? .DIR ,P?STARBOARD>\n\t\t<TELL \"starboard\">)\n\t       (<EQUAL? .DIR ,P?FORE>\n\t\t<TELL \"straight\">)>>"
  },
