   "file": "globals.zil",
   "line": 243,
   "endLine": 248,
   "source": "<ROUTINE LG-HOLE-F ()\n\t <COND (<P? DIG LG-HOLE *>\n\t\t<PERFORM ,V?DIG ,PRSI>\n\t\t<RTRUE>)\n\t       (<VERB? REACH-IN>\n\t\t<TELL ,YOU-FIND-NOTHING \" of interest.\" CR>)>>"
