  "JAPANESE-PHRASES": {
   "name": "JAPANESE-PHRASES",
   "kind": "constant",
   "file": "cast.zil",
   "line": 2192,
   "value": "<LTABLE (PURE) <PHRASE \"ANATA\" \"WA\" \"YOKU\" \"NEMUTTA\" \"KA\"> \"Did you sleep well?\" <PHRASE \"ARIGATO\" \"GOZIEMASHITA\"> \"Thank you, from an inferior to a superior.\" <PHRASE \"DOKO\" \"NO\" \"KUNI\" \"NO\" \"MONODA\"> \"What's your nationality?\" <PHRASE \"GENKI\" \"DESU\"> \"Quite well.\" <PHRASE \"GOMEN\" \"NASAI\"> \"So sorry.\" <PHRASE \"IKAGA\" \"DESU\" \"KA\"> \"How are you?\" <PHRASE \"KONNICHI\" \"WA\"> \"Good day.\" <PHRASE \"ONUSHI\" \"ITTAI\" \"DOKO\" \"KARA\" \"KITANODA\"> \"Where are you from?\" <PHRASE \"SHIGATA\" \"GA\" \"NAI\"> \"There's nothing that can be done.\" <PHRASE \"TSUYUKU\" \"GA\" \"IMASU\" \"KA\"> \"Do you have an interpreter?\" <PHRASE \"WAKARIMASU\" \"KA\"> \"Do you understand?\">"
  },
